import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ChevronLeft, ChevronRight, Trash2, X, Save, Receipt, Hash } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Listagem.css';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]); 
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  
  const [modal, setModal] = useState({ 
    isOpen: false, type: 'success', title: '', message: '', onConfirm: null 
  });

  const [filtroData, setFiltroData] = useState({
    mes: new Date().getMonth(),
    ano: new Date().getFullYear()
  });

  const mesesNominais = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];
  const formasPagamento = ["Boleto", "Crédito", "Débito", "Dinheiro", "Pix", "Transferência"].sort();

  useEffect(() => {
    carregarDadosIniciais();
  }, [filtroData]);

  async function carregarDadosIniciais() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).single();
    setPerfilLogado(meuPerfil);
    
    // Carrega cartões e usuários para os selects do modal de edição
    const { data: dCartoes } = await supabase.from('cartoes').select('id, nome').order('nome');
    const { data: dUsers } = await supabase.from('profiles').select('id, nome').order('nome');
    setCartoes(dCartoes || []);
    setUsuarios(dUsers || []);
    
    fetchDespesas(meuPerfil);
  }

  async function fetchDespesas(perfil) {
    let query = supabase.from('compras').select('*, profiles(nome)').order('data_compra', { ascending: false });
    if (perfil?.tipo_usuario !== 'proprietario') query = query.eq('user_id', perfil.id);
    
    const { data, error } = await query;
    if (!error && data) {
      const projetadas = [];
      data.forEach(item => {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const [ano, mes, dia] = item.data_compra.split('-');
          const dataCompra = new Date(ano, mes - 1, dia);
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({ 
              ...item, 
              parcelaAtual: i + 1, 
              valorParcela: parseFloat(item.valor_total) / numParcelas, 
              nomeResponsavel: item.profiles?.nome || '⚠️ Pendente' 
            });
          }
        }
      });
      setDespesas(projetadas);
    }
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    const isCredito = itemParaEditar.forma_pagamento === 'Crédito';

    const { error } = await supabase.from('compras').update({
      descricao: itemParaEditar.descricao,
      loja: itemParaEditar.loja,
      user_id: itemParaEditar.user_id, 
      valor_total: parseFloat(itemParaEditar.valor_total),
      forma_pagamento: itemParaEditar.forma_pagamento,
      cartao: isCredito ? itemParaEditar.cartao : 'À Vista',
      data_compra: itemParaEditar.data_compra,
      num_parcelas: isCredito ? parseInt(itemParaEditar.num_parcelas) : 1,
      parcelado: isCredito && parseInt(itemParaEditar.num_parcelas) > 1,
      numero_pedido: itemParaEditar.numero_pedido,
      nota_fiscal: itemParaEditar.nota_fiscal
    }).eq('id', itemParaEditar.id);

    if (error) {
      setModal({ isOpen: true, type: 'error', title: 'Erro', message: error.message });
    } else {
      setItemParaEditar(null);
      setModal({ isOpen: true, type: 'success', title: 'Atualizado', message: 'Dados salvos com sucesso!' });
      fetchDespesas(perfilLogado);
    }
  };

  const confirmDelete = (id) => {
    setModal({
      isOpen: true,
      type: 'error',
      title: 'Excluir Gasto?',
      message: 'Esta ação removerá o gasto original e todas as suas parcelas.',
      onConfirm: () => handleDelete(id)
    });
  };

  const handleDelete = async (id) => {
    const { error } = await supabase.from('compras').delete().eq('id', id);
    if (!error) {
      setItemParaEditar(null);
      setModal({ isOpen: true, type: 'success', title: 'Excluído', message: 'Registro removido.' });
      fetchDespesas(perfilLogado);
    }
  };

  const mudarMes = (direcao) => {
    let novoMes = filtroData.mes + direcao;
    let novoAno = filtroData.ano;
    if (novoMes < 0) { novoMes = 11; novoAno--; }
    else if (novoMes > 11) { novoMes = 0; novoAno++; }
    setFiltroData({ mes: novoMes, ano: novoAno });
  };

  const labelStyle = { fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block', textTransform: 'uppercase' };

  return (
    <div className="listagem-container fade-in">
      <div className="listagem-header">
        <div>
          <h2>Extrato de Gastos</h2>
          <p>Detalhamento mensal de lançamentos</p>
        </div>
        <div className="date-navigator">
          <button onClick={() => mudarMes(-1)} className="nav-btn"><ChevronLeft size={20} /></button>
          <div style={{ textAlign: 'center', minWidth: '110px' }}>
            <span style={{ display: 'block', fontWeight: 800, fontSize: '0.9rem' }}>{mesesNominais[filtroData.mes]}</span>
            <span style={{ color: '#94a3b8', fontSize: '0.75rem', fontWeight: 600 }}>{filtroData.ano}</span>
          </div>
          <button onClick={() => mudarMes(1)} className="nav-btn"><ChevronRight size={20} /></button>
        </div>
      </div>

      <div className="table-wrapper">
        <table className="custom-table">
          <thead>
            <tr>
              <th>Data</th>
              <th>Responsável</th>
              <th>Descrição</th>
              <th>Doc/Pedido</th>
              <th>Cartão</th>
              <th>Parcela</th>
              <th style={{ textAlign: 'right' }}>Valor Parcela</th>
            </tr>
          </thead>
          <tbody>
            {despesas.map((item, idx) => (
              <tr key={`${item.id}-${idx}`} 
                  className={perfilLogado?.tipo_usuario === 'proprietario' ? 'clickable-row' : ''} 
                  onClick={() => perfilLogado?.tipo_usuario === 'proprietario' && setItemParaEditar(item)}>
                <td>{item.data_compra.split('-').reverse().slice(0,2).join('/')}</td>
                <td style={{ fontWeight: '700', color: '#4361ee' }}>{item.nomeResponsavel}</td>
                <td>
                    <div style={{fontWeight: '600', color: '#1e293b'}}>{item.descricao}</div>
                    <div style={{fontSize: '0.65rem', color: '#94a3b8'}}>{item.loja}</div>
                </td>
                <td>
                  <div style={{fontSize: '0.75rem', color: '#64748b'}}>
                    {item.numero_pedido && <span>📦 {item.numero_pedido}</span>}
                    {item.nota_fiscal && <div style={{fontSize: '0.65rem'}}>📄 NF: {item.nota_fiscal}</div>}
                    {!item.numero_pedido && !item.nota_fiscal && '-'}
                  </div>
                </td>
                <td>{item.cartao || 'À Vista'}</td>
                <td>
                  <span className="badge-parcela" style={{ background: item.parcelado ? '#eef2ff' : '#f0fdf4', color: item.parcelado ? '#4361ee' : '#16a34a' }}>
                    {item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}
                  </span>
                </td>
                <td style={{ fontWeight: '800', textAlign: 'right', color: '#0f172a' }}>
                  R$ {item.valorParcela.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {itemParaEditar && (
        <div className="edit-modal-overlay">
          <div className="edit-modal-content">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
              <h3 style={{ margin: 0, fontWeight: 800 }}>Editar Lançamento</h3>
              <button onClick={() => setItemParaEditar(null)} className="btn-close-modal"><X /></button>
            </div>

            <form onSubmit={handleUpdate} className="edit-form">
              <div className="grid-2">
                <div>
                  <label style={labelStyle}>Data da Compra</label>
                  <input type="date" className="form-control" value={itemParaEditar.data_compra || ''} onChange={e => setItemParaEditar({...itemParaEditar, data_compra: e.target.value})} required />
                </div>
                <div>
                  <label style={labelStyle}>Responsável</label>
                  <select className="form-control" value={itemParaEditar.user_id || ''} onChange={e => setItemParaEditar({...itemParaEditar, user_id: e.target.value})} required>
                    {usuarios.map(u => <option key={u.id} value={u.id}>{u.nome}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid-2">
                <div>
                  <label style={labelStyle}>N° do Pedido</label>
                  <input className="form-control" placeholder="Ex: 100234" value={itemParaEditar.numero_pedido || ''} onChange={e => setItemParaEditar({...itemParaEditar, numero_pedido: e.target.value})} />
                </div>
                <div>
                  <label style={labelStyle}>Nota Fiscal (NF)</label>
                  <input className="form-control" placeholder="Ex: 4509" value={itemParaEditar.nota_fiscal || ''} onChange={e => setItemParaEditar({...itemParaEditar, nota_fiscal: e.target.value})} />
                </div>
              </div>

              <div>
                <label style={labelStyle}>Descrição / Produto</label>
                <input className="form-control" value={itemParaEditar.descricao} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} />
              </div>

              <div className="grid-2">
                <div>
                  <label style={labelStyle}>Loja</label>
                  <input className="form-control" value={itemParaEditar.loja || ''} onChange={e => setItemParaEditar({...itemParaEditar, loja: e.target.value})} />
                </div>
                <div>
                  <label style={labelStyle}>Valor Total</label>
                  <input type="number" step="0.01" className="form-control" value={itemParaEditar.valor_total} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} />
                </div>
              </div>

              <div className="grid-2">
                <div>
                  <label style={labelStyle}>Forma de Pagamento</label>
                  <select className="form-control" value={itemParaEditar.forma_pagamento} onChange={e => setItemParaEditar({...itemParaEditar, forma_pagamento: e.target.value})}>
                    {formasPagamento.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                </div>
                
                {itemParaEditar.forma_pagamento === 'Crédito' && (
                  <div>
                    <label style={labelStyle}>Cartão Utilizado</label>
                    <select className="form-control" value={itemParaEditar.cartao} onChange={e => setItemParaEditar({...itemParaEditar, cartao: e.target.value})}>
                      <option value="">Selecione...</option>
                      {cartoes.map(c => <option key={c.id} value={c.nome}>{c.nome}</option>)}
                    </select>
                  </div>
                )}
              </div>

              {itemParaEditar.forma_pagamento === 'Crédito' && (
                <div>
                  <label style={labelStyle}>Número de Parcelas</label>
                  <input type="number" min="1" className="form-control" value={itemParaEditar.num_parcelas || 1} onChange={e => setItemParaEditar({...itemParaEditar, num_parcelas: e.target.value})} />
                </div>
              )}

              <div className="edit-modal-footer">
                <button type="submit" className="btn-update">
                  <Save size={18} /> Atualizar Lançamento
                </button>
                <button type="button" className="btn-delete-action" onClick={() => confirmDelete(itemParaEditar.id)}>
                  <Trash2 size={20} />
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <ModalFeedback 
        isOpen={modal.isOpen}
        type={modal.type}
        title={modal.title}
        message={modal.message}
        onClose={() => setModal({ ...modal, isOpen: false })}
        onConfirm={modal.onConfirm}
      />
    </div>
  );
};

export default Listagem;
